// 自由記入スタイル: ユーザーが書いた語り口指示をそのままペルソナとして使う(mode="custom")。
// 語り口テキストは専用キーに保存し、次回以降も使い回せる。
let CUSTOM_PERSONA_TEXT = "";
async function loadCustomPersona() {
  try { const v = await sGet("blt_custom_persona_v1", false); if (v && typeof v.text === "string") CUSTOM_PERSONA_TEXT = v.text; } catch (e) {}
  return CUSTOM_PERSONA_TEXT;
}
async function saveCustomPersona(text) {
  CUSTOM_PERSONA_TEXT = (text || "").trim();
  try { await sSet("blt_custom_persona_v1", { text: CUSTOM_PERSONA_TEXT }); } catch (e) {}
}

