          <div style={{ writingMode: "vertical-rl", fontSize: "15px", fontWeight: 900, color: l.rarity === "legendary" ? "#fff0b8" : C.yellow, letterSpacing: "0.16em", maxHeight: "130px", overflow: "hidden", flexShrink: 0, lineHeight: 1.3, textShadow: l.rarity === "legendary" ? "0 0 12px rgba(255,224,102,0.6)" : "none" }}>{l.headline || "—"}</div>
